// mm/src/store/workflowContext.js
import React, { createContext, useContext, useMemo, useState } from 'react';

const WorkflowContext = createContext(null);

export const WorkflowProvider = ({ children }) => {
  // Upload phase controls what the Upload route renders:
  // select   -> initial upload dropzone
  // ready    -> after at least one file uploaded (shows "Start AI Analysis" button)
  // metadata -> Basic Information + Organize Your Files (your screenshot)
  const [uploadPhase, setUploadPhase] = useState('select');

  // Book details collected in metadata
  const [bookDetails, setBookDetails] = useState({
    title: '',
    author: '',
    category: '',
    subcategory: '',
  });

  // Manuscript files in upload step
  const [manuscriptFiles, setManuscriptFiles] = useState([]);

  // Design choices
  const [design, setDesign] = useState({
    analyzed: false,
    stage: 'typography', // typography -> layout -> trim -> summary
    typography: null,
    layout: null,
    trim: null,
  });

  // ---- helpers ----
  // Upsert (replace by id if exists; otherwise add)
  const upsertFile = (fileMeta) => {
    setManuscriptFiles((prev) => {
      const idx = prev.findIndex((f) => f.id === fileMeta.id);
      if (idx === -1) return [...prev, fileMeta];
      const next = [...prev];
      next[idx] = { ...next[idx], ...fileMeta };
      return next;
    });
  };

  const removeFile = (id) => {
    setManuscriptFiles((prev) => prev.filter((f) => f.id !== id));
  };

  const value = useMemo(
    () => ({
      uploadPhase,
      setUploadPhase,

      bookDetails,
      setBookDetails,

      manuscriptFiles,
      setManuscriptFiles,
      addFile: upsertFile, // keep  existing API name
      removeFile,

      design,
      setDesign,
    }),
    [uploadPhase, bookDetails, manuscriptFiles, design]
  );

  return (
    <WorkflowContext.Provider value={value}>
      {children}
    </WorkflowContext.Provider>
  );
};

export const useWorkflow = () => {
  const ctx = useContext(WorkflowContext);
  if (!ctx) throw new Error('useWorkflow must be used inside WorkflowProvider');
  return ctx;
};
